{
  "manifest_version": 3,
  "name": "GovTranslate",
  "version": "1.0.0",
  "permissions": ["storage", "activeTab", "scripting"],
  "host_permissions": ["https://api.anthropic.com/*"],
  "background": {
    "service_worker": "background.js"
  },
  "action": {
    "default_popup": "popup.html"
  },
  "content_scripts": [
    {
      "matches": ["<all_urls>"],
      "js": ["content.js"]
    }
  ]
}

// content.js
chrome.runtime.sendMessage({
  type: "TRANSLATE_SELECTION",
  text: window.getSelection().toString()
}, (response) => {
  if (response?.translatedText) {
    console.log(response.translatedText);
  }
});

// background.js
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type !== "TRANSLATE_SELECTION") return;

  (async () => {
    const { anthropicApiKey } = await chrome.storage.sync.get("anthropicApiKey");

    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "content-type": "application/json",
        "x-api-key": anthropicApiKey,
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true"
      },
      body: JSON.stringify({
        model: "claude-3-5-haiku-latest",
        max_tokens: 512,
        messages: [
          {
            role: "user",
            content: `Translate this text clearly and faithfully:\n\n${message.text}`
          }
        ]
      })
    });

    const data = await response.json();
    const translatedText = data.content?.[0]?.text ?? "";
    sendResponse({ translatedText });
  })();

  return true;
});
